 1	import * as React from 'react';
 2	import CapacityCard from '@odf/shared/dashboards/capacity-card/capacity-card';
 3	import { FieldLevelHelp } from '@odf/shared/generic';
 4	import {
 5	  useCustomPrometheusPoll,
 6	  usePrometheusBasePath,
 7	} from '@odf/shared/hooks/custom-prometheus-poll';
 8	import { ODFStorageSystem } from '@odf/shared/models';
 9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
10	import { humanizeBinaryBytes } from '@odf/shared/utils/humanize';
11	import { parseMetricData } from '@odf/shared/utils/metrics';
12	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
13	import { externalStorageCapacityUsed } from '../../../constants';
14	import { StorageDashboard, CAPACITY_QUERIES } from '../queries';
15	
16	const ObjectCapacityCard: React.FC = () => {
17	  const { t } = useCustomTranslation();
18	  const [data, error, loading] = useCustomPrometheusPoll({
19	    query: CAPACITY_QUERIES[StorageDashboard.USED_CAPACITY_OBJECT],
20	    endpoint: 'api/v1/query' as any,
21	    basePath: usePrometheusBasePath(),
22	  });
23	
24	  const dataFrames =
25	    !loading && !error
26	      ? parseMetricData(data, humanizeBinaryBytes, 'type')
27	      : [];
28	
29	  return (
30	    <Card className="odf-capacityCard--height">
31	      <CardHeader>
32	        <CardTitle>
33	          {t('External object provider used capacity')}
34	          <FieldLevelHelp>{externalStorageCapacityUsed(t)}</FieldLevelHelp>
35	        </CardTitle>
36	      </CardHeader>
37	      <CardBody>
38	        <CapacityCard
39	          isExternalObjectCapacityCard
40	          data={dataFrames}
41	          relative
42	          showPercentage={false}
43	          resourceModel={ODFStorageSystem}
44	        />
45	      </CardBody>
46	    </Card>
47	  );
48	};
49	
50	export default ObjectCapacityCard;

